#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=6e6+10;
int head[N],des[N],nxt[N],cgt=1;
vector<int> sl[N];
inline void ins(int x,int y)
{
	if(x==y)des[++cgt]=x,des[++cgt]=y,sl[x].push_back(cgt>>1);
	else
	{
		nxt[++cgt]=head[x];des[head[x]=cgt]=y;
		nxt[++cgt]=head[y];des[head[y]=cgt]=x;
	}
}
map<int,int> idx; int n,m;
typedef pair<int,int> pii;
vector<pii> ans;int loc[N];
vector<pair<int,pii>> res;
int dfn[N],cdt;
inline int dfs(int u,int fa=0)
{
	dfn[u]=++cdt;int lst=0;
	grep(u,i)if(i!=fa)
	{
//		printf("QAQ::%d\n",des[i]);
		int v=des[i];if(!dfn[v])
		{
			int x=dfs(v,i^1);
			if(x)ans.push_back({i>>1,x});
			else
			{
				if(!lst)lst=i>>1;
				else ans.push_back({lst,i>>1}),lst=0;
			}
//			printf("cnm %d :: %d\n",u,i>>1);
		}
		else if(dfn[v]>dfn[u])
		{
			if(!lst)lst=i>>1;
			else ans.push_back({lst,i>>1}),lst=0;
//			printf("cnm %d :: %d\n",u,i>>1);
		}
	}
	for(int v:sl[u]){if(!lst)lst=v;else ans.push_back({lst,v}),lst=0;}
//	printf("%d :: %d %d\n",lst,des[lst],des[lst^1]);
	return lst;
}
int db;
int main()
{
	m=read();rep(1,m,i)
	{
		int x=read(),y=read();
		if(!idx.count(x))loc[idx[x]=++n]=x;
		if(!idx.count(y))loc[idx[y]=++n]=y;
		ins(idx[x],idx[y]);
	}
	rep(1,n,i)if(!dfn[i])
	{
		unsigned lst=ans.size();int x=dfs(i);
		if(ans.size()==lst){puts("-1");return 0;}
		if(x){res.push_back({x,*prev(ans.end())});ans.pop_back();}
	}
//	puts("<<<");
//	rep(1,m,i)printf("%d %d\n",des[i<<1],des[i<<1|1]);
//	rep(1,n,i)printf("%d ",loc[i]);puts("");
//	puts("<<<");
//	rep(9,11,i)printf("QAQ QAQ :: (%d %d)\n",des[i<<1],des[i<<1|1]);
	printf("%d 2\n\n",m);
	int c1=0,c2=0;
	for(pii v:ans)
	{
		int i=v.first,j=v.second; ++c1;
//		printf("QAQ :: %d -> %d %d\n",++db,i,j); 
		int p[4]={des[i<<1],des[i<<1|1],des[j<<1],des[j<<1|1]};
//		rep(0,3,i)printf("%d ",p[i]);puts("");
		rep(0,1,i)
		{
			bool flag=false;
			rep(2,3,j)if(p[i]==p[j])
			{
				printf("%d %d\n",loc[p[i^1]],loc[p[i]]);
				printf("%d %d\n",loc[p[j]],loc[p[j^1]]);
				flag=true;break;
			}
			if(flag)break;
		}
	}
	for(pair<int,pii> &v:res)
	{
		int i=v.first,j=v.second.first,k=v.second.second; ++c2;
//		printf("QAQ :: %d -> %d %d %d\n",++db,i,j,k);
		int X[3]={des[i<<1],des[j<<1],des[k<<1]},Y[3]={des[i<<1|1],des[j<<1|1],des[k<<1|1]},p[3]={0,1,2};
		do
		{
			bool flag=0;
			rep(0,7,S)
			{
				int x[3],y[3];rep(0,2,i)x[i]=X[p[i]],y[i]=Y[p[i]];
				rep(0,2,i)if(S>>i&1)swap(x[i],y[i]);
				if(y[0]==x[1]&&y[1]==x[2])
				{
					rep(0,2,i)printf("%d %d\n",loc[x[i]],loc[y[i]]);
					flag=true;break;
				}
				if(x[0]==x[1]&&x[1]==x[2])
				{
					swap(x[1],y[1]);
					rep(0,2,i)printf("%d %d\n",loc[x[i]],loc[y[i]]);
					flag=true;break;
				}
			}
			if(flag)break;
		}
		while(next_permutation(p,p+2));
	}
	puts("");rep(1,c1,i)puts("LR\nLR");rep(1,c2,i)puts("LR\nUU\nDD");puts("");
	rep(1,c1,i)puts("UU\nDD");rep(1,c2,i)puts("UU\nDD\nLR");puts("");return 0;
}
